changeSet.sql:
DO $seed$
DECLARE
    org_id UUID;
    cashier_id UUID;
    cashier_role TEXT;
    d DATE;
    n INT;
    marker TEXT;
    svc_code TEXT;
    svc RECORD;
    primary_th RECORD;
    secondary_th_id UUID;
    secondary_th_nickname TEXT;
    secondary_th_gender TEXT;
    chosen_room RECORD;
    chosen_bed UUID;
    is_tandem BOOLEAN;
    booking_id UUID;
    session_id UUID;
    slip_id UUID;
    order_id UUID;
    order_item_id UUID;
    order_item_pkg_id BIGINT;
    tx_id UUID;
    start_ts TIMESTAMPTZ;
    end_ts TIMESTAMPTZ;
    svc_price NUMERIC(12,2);
    svc_minutes INT;
    commission_total NUMERIC(12,2);
    nick TEXT;
    locker TEXT;
    or_no TEXT;
    rc_no TEXT;
    tsn_no TEXT;
    pay_method TEXT;
    rating INT;
    therapist_codes TEXT[] := ARRAY['TH001','TH002','TH003','TH004','TH005'];
    service_codes TEXT[] := ARRAY['SWEDISH','SHIATSU','FOOT_REFLEX','DEEP_TISSUE','TANDEM','AROMA_REFLEX','THAI','COMBINATION'];
    payment_methods TEXT[] := ARRAY['CASH','GCASH','CREDIT','DEBIT'];
    nicknames TEXT[] := ARRAY['Maya','Leo','Tala','Ren','Kit','Bea','Nio','Sky','Joy','Dex'];
    room_count INT;
BEGIN
    SELECT id INTO org_id FROM organizations WHERE slug = 'lasema';
    SELECT id, (SELECT code FROM roles WHERE id = users.role_id) INTO cashier_id, cashier_role
        FROM users WHERE username = 'superadmin';

    SELECT COUNT(*) INTO room_count FROM rooms WHERE organization_id = org_id AND is_active = true;
    IF room_count = 0 THEN
        RETURN;
    END IF;

    SELECT id INTO order_item_pkg_id FROM packages
        WHERE organization_id = org_id ORDER BY id LIMIT 1;

    FOR d IN SELECT generate_series('2026-05-15'::date, '2026-06-14'::date, '1 day')::date LOOP
        FOR n IN 1..8 LOOP
            marker := 'SEED-' || to_char(d, 'YYYYMMDD') || '-' || lpad(n::text, 2, '0');

            IF EXISTS (SELECT 1 FROM bookings WHERE organization_id = org_id AND remarks = marker) THEN
                CONTINUE;
            END IF;

            svc_code := service_codes[((d - DATE '2026-05-15') * 8 + (n - 1)) % array_length(service_codes, 1) + 1];
            SELECT id, name, price, duration_minutes, requires_two_therapists
                INTO svc
                FROM services_catalogue
                WHERE organization_id = org_id AND code = svc_code;
            IF svc.id IS NULL THEN
                CONTINUE;
            END IF;
            svc_price := svc.price;
            svc_minutes := svc.duration_minutes;
            is_tandem := svc.requires_two_therapists;

            SELECT id, nickname, gender INTO primary_th
                FROM therapists
                WHERE organization_id = org_id
                  AND staff_number = therapist_codes[((n - 1) % array_length(therapist_codes, 1)) + 1];

            secondary_th_id := NULL;
            secondary_th_nickname := NULL;
            secondary_th_gender := NULL;
            IF is_tandem THEN
                SELECT id, nickname, gender INTO secondary_th_id, secondary_th_nickname, secondary_th_gender
                    FROM therapists
                    WHERE organization_id = org_id
                      AND staff_number = therapist_codes[(n % array_length(therapist_codes, 1)) + 1];
            END IF;

            SELECT id, room_number INTO chosen_room
                FROM rooms
                WHERE organization_id = org_id AND is_active = true
                ORDER BY room_number
                OFFSET ((n - 1) % room_count) LIMIT 1;

            SELECT id INTO chosen_bed
                FROM beds
                WHERE room_id = chosen_room.id AND is_active = true
                ORDER BY bed_label
                LIMIT 1;

            commission_total := ROUND(120.00 * svc_minutes / 60.0, 2);

            start_ts := (d::timestamp + make_interval(hours => 8 + n)) AT TIME ZONE 'Asia/Manila';
            end_ts := start_ts + make_interval(mins => svc_minutes);

            nick := nicknames[((d - DATE '2026-05-15') + n) % array_length(nicknames, 1) + 1];
            locker := 'L' || lpad((((n - 1) % 40) + 1)::text, 3, '0');
            or_no := 'SEEDOR-' || to_char(d, 'YYYYMMDD') || '-' || lpad(n::text, 2, '0');
            rc_no := 'SEEDRC-' || to_char(d, 'YYYYMMDD') || '-' || lpad(n::text, 2, '0');
            tsn_no := 'SEEDTS-' || to_char(d, 'YYYYMMDD') || '-' || lpad(n::text, 2, '0');
            pay_method := payment_methods[((n - 1) % array_length(payment_methods, 1)) + 1];

            booking_id := gen_random_uuid();
            INSERT INTO bookings (id, reference, organization_id, client_nickname, locker_number, service_id,
                                  reservation_type, scheduled_at, actual_start_at, actual_end_at, pax,
                                  client_gender, remarks, status, payment_status, created_at)
            VALUES (booking_id, 'S' || to_char(d, 'MMDD') || lpad(n::text, 2, '0'), org_id, nick, locker, svc.id,
                    'WALK_IN', start_ts, start_ts, end_ts, 1,
                    primary_th.gender, marker, 'COMPLETED', 'PAID', start_ts);

            session_id := gen_random_uuid();
            INSERT INTO sessions (id, booking_id, organization_id, primary_therapist_id, secondary_therapist_id,
                                  room_id, bed_id, is_specifically_requested, is_extension, extension_minutes,
                                  status, started_at, ended_at, created_at)
            VALUES (session_id, booking_id, org_id, primary_th.id,
                    secondary_th_id,
                    chosen_room.id, chosen_bed, false, false, 0,
                    'ENDED', start_ts, end_ts, start_ts);

            slip_id := gen_random_uuid();
            INSERT INTO treatment_slips (id, organization_id, tsn, booking_id, session_id, client_nickname,
                                         locker_number, primary_therapist_nickname, secondary_therapist_nickname,
                                         service_name, room_number, start_time, end_time, is_vip, status,
                                         pax, treatment_minutes, or_number, total_amount, waiver_accepted,
                                         signed_at, created_at)
            VALUES (slip_id, org_id, tsn_no, booking_id, session_id, nick,
                    locker, primary_th.nickname,
                    secondary_th_nickname,
                    svc.name, chosen_room.room_number, start_ts, end_ts, false, 'FINALIZED',
                    1, svc_minutes, or_no, svc_price, true,
                    end_ts, start_ts);

            order_id := gen_random_uuid();
            INSERT INTO orders (id, organization_id, booking_id, treatment_slip_id, cashier_user_id, or_number,
                                subtotal, discount, tax, total, amount_paid, status, transactor_name,
                                is_group_booking, room_type, room_type_charge, is_weekend,
                                created_at, completed_at, finished_at)
            VALUES (order_id, org_id, booking_id, slip_id, cashier_id, or_no,
                    svc_price, 0, 0, svc_price, svc_price, 'PAID', nick,
                    false, 'COMMON', 0, (EXTRACT(ISODOW FROM d) >= 6),
                    start_ts, end_ts, end_ts);

            IF order_item_pkg_id IS NOT NULL THEN
                order_item_id := gen_random_uuid();
                INSERT INTO order_items (id, order_id, organization_id, package_id, quantity, unit_price,
                                         line_total, position, created_at)
                VALUES (order_item_id, order_id, org_id, order_item_pkg_id, 1, svc_price,
                        svc_price, 0, start_ts);

                INSERT INTO order_item_attendees (order_item_id, order_id, organization_id, service_id,
                                                  locker_number, client_gender, session_id, treatment_slip_id,
                                                  position, created_at)
                VALUES (order_item_id, order_id, org_id, svc.id,
                        locker, primary_th.gender, session_id, slip_id,
                        0, start_ts);
            END IF;

            tx_id := gen_random_uuid();
            INSERT INTO transactions (id, organization_id, session_id, order_id, receipt_number, subtotal, discount, total,
                                      payment_method, processed_by, processed_at, status)
            VALUES (tx_id, org_id, session_id, order_id, rc_no, svc_price, 0, svc_price,
                    pay_method, cashier_id, end_ts, 'COMPLETED');

            INSERT INTO transaction_ledger (organization_id, transaction_id, entry_type, amount, recorded_at,
                                            payment_method, status)
            VALUES (org_id, tx_id, 'PAYMENT_RECEIVED', svc_price, end_ts, pay_method, 'COMPLETED');

            IF is_tandem AND secondary_th_id IS NOT NULL THEN
                INSERT INTO commissions (organization_id, session_id, therapist_id, amount, is_extension, is_backup, created_at)
                VALUES (org_id, session_id, primary_th.id, ROUND(commission_total / 2.0, 2), false, false, end_ts);
                INSERT INTO commissions (organization_id, session_id, therapist_id, amount, is_extension, is_backup, created_at)
                VALUES (org_id, session_id, secondary_th_id, commission_total - ROUND(commission_total / 2.0, 2), false, false, end_ts);
            ELSE
                INSERT INTO commissions (organization_id, session_id, therapist_id, amount, is_extension, is_backup, created_at)
                VALUES (org_id, session_id, primary_th.id, commission_total, false, false, end_ts);
            END IF;

            INSERT INTO audit_logs (organization_id, actor_user_id, actor_role, action_type, target_entity,
                                    target_id, metadata, ip_address, occurred_at)
            VALUES (org_id, cashier_id, COALESCE(cashier_role, 'SUPERADMIN'), 'ORDER.PAID', 'ORDER',
                    order_id::text, '{"seed":true,"reference":"' || marker || '"}', '127.0.0.1', end_ts);

            IF (n % 4) = 0 THEN
                rating := 3 + (n % 3);
                INSERT INTO feedback (organization_id, session_id, rating_stars, comment, or_number, submitted_at)
                VALUES (org_id, session_id, rating, 'Relaxing session, thank you.', or_no,
                        end_ts + make_interval(mins => 30));
            END IF;
        END LOOP;
    END LOOP;
END
$seed$;

DO $dayrep$
DECLARE
    org_id UUID;
    d DATE;
    from_ts TIMESTAMPTZ;
    to_ts TIMESTAMPTZ;
    session_count INT;
    commission_count INT;
    payload TEXT;
BEGIN
    SELECT id INTO org_id FROM organizations WHERE slug = 'lasema';

    FOR d IN SELECT generate_series('2026-05-15'::date, '2026-06-14'::date, '1 day')::date LOOP
        IF EXISTS (SELECT 1 FROM day_reports WHERE organization_id = org_id AND report_date = d) THEN
            CONTINUE;
        END IF;

        from_ts := d::timestamp AT TIME ZONE 'Asia/Manila';
        to_ts := (d + 1)::timestamp AT TIME ZONE 'Asia/Manila';

        SELECT COUNT(*) INTO session_count
            FROM sessions
            WHERE organization_id = org_id AND status <> 'CANCELLED'
              AND started_at >= from_ts AND started_at < to_ts;
        SELECT COUNT(*) INTO commission_count
            FROM commissions
            WHERE organization_id = org_id AND created_at >= from_ts AND created_at < to_ts;

        payload := '{"from":"' || to_char(from_ts AT TIME ZONE 'UTC', 'YYYY-MM-DD"T"HH24:MI:SS"Z"')
                || '","to":"' || to_char(to_ts AT TIME ZONE 'UTC', 'YYYY-MM-DD"T"HH24:MI:SS"Z"')
                || '","sessionCount":' || session_count
                || ',"commissionCount":' || commission_count
                || ',"commissionsByTherapist":' || COALESCE((
                        SELECT '{' || string_agg('"' || therapist_id::text || '":' || total::text, ',') || '}'
                        FROM (
                            SELECT therapist_id, SUM(amount) AS total
                            FROM commissions
                            WHERE organization_id = org_id AND created_at >= from_ts AND created_at < to_ts
                            GROUP BY therapist_id
                        ) c
                   ), '{}')
                || ',"sessionCountByTherapist":' || COALESCE((
                        SELECT '{' || string_agg('"' || primary_therapist_id::text || '":' || cnt::text, ',') || '}'
                        FROM (
                            SELECT primary_therapist_id, COUNT(*) AS cnt
                            FROM sessions
                            WHERE organization_id = org_id AND status <> 'CANCELLED'
                              AND started_at >= from_ts AND started_at < to_ts
                              AND primary_therapist_id IS NOT NULL
                            GROUP BY primary_therapist_id
                        ) s
                   ), '{}')
                || ',"requestedCountByTherapist":{}}';

        INSERT INTO day_reports (organization_id, report_date, payload, generated_at)
        VALUES (org_id, d, payload, to_ts);
    END LOOP;
END
$dayrep$;

DO $monrep$
DECLARE
    org_id UUID;
    period RECORD;
    from_ts TIMESTAMPTZ;
    to_ts TIMESTAMPTZ;
    session_count INT;
    commission_count INT;
    day_count INT;
    summary TEXT;
    payload TEXT;
BEGIN
    SELECT id INTO org_id FROM organizations WHERE slug = 'lasema';

    FOR period IN
        SELECT 2026 AS yr, 5 AS mo, DATE '2026-05-15' AS p_from, DATE '2026-06-01' AS p_to
        UNION ALL
        SELECT 2026 AS yr, 6 AS mo, DATE '2026-06-01' AS p_from, DATE '2026-06-15' AS p_to
    LOOP
        IF EXISTS (SELECT 1 FROM monthly_reports WHERE organization_id = org_id
                   AND report_year = period.yr AND report_month = period.mo) THEN
            CONTINUE;
        END IF;

        from_ts := period.p_from::timestamp AT TIME ZONE 'Asia/Manila';
        to_ts := period.p_to::timestamp AT TIME ZONE 'Asia/Manila';

        SELECT COUNT(*) INTO session_count
            FROM sessions
            WHERE organization_id = org_id AND status <> 'CANCELLED'
              AND started_at >= from_ts AND started_at < to_ts;
        SELECT COUNT(*) INTO commission_count
            FROM commissions
            WHERE organization_id = org_id AND created_at >= from_ts AND created_at < to_ts;
        SELECT COUNT(*) INTO day_count
            FROM day_reports
            WHERE organization_id = org_id AND report_date >= period.p_from AND report_date < period.p_to;

        summary := '{"from":"' || to_char(from_ts AT TIME ZONE 'UTC', 'YYYY-MM-DD"T"HH24:MI:SS"Z"')
                || '","to":"' || to_char(to_ts AT TIME ZONE 'UTC', 'YYYY-MM-DD"T"HH24:MI:SS"Z"')
                || '","sessionCount":' || session_count
                || ',"commissionCount":' || commission_count
                || ',"commissionsByTherapist":' || COALESCE((
                        SELECT '{' || string_agg('"' || therapist_id::text || '":' || total::text, ',') || '}'
                        FROM (
                            SELECT therapist_id, SUM(amount) AS total
                            FROM commissions
                            WHERE organization_id = org_id AND created_at >= from_ts AND created_at < to_ts
                            GROUP BY therapist_id
                        ) c
                   ), '{}')
                || ',"sessionCountByTherapist":' || COALESCE((
                        SELECT '{' || string_agg('"' || primary_therapist_id::text || '":' || cnt::text, ',') || '}'
                        FROM (
                            SELECT primary_therapist_id, COUNT(*) AS cnt
                            FROM sessions
                            WHERE organization_id = org_id AND status <> 'CANCELLED'
                              AND started_at >= from_ts AND started_at < to_ts
                              AND primary_therapist_id IS NOT NULL
                            GROUP BY primary_therapist_id
                        ) s
                   ), '{}')
                || ',"requestedCountByTherapist":{}}';

        payload := '{"summary":' || summary || ',"dayCount":' || day_count || '}';

        INSERT INTO monthly_reports (organization_id, report_year, report_month, payload, generated_at)
        VALUES (org_id, period.yr, period.mo, payload, to_ts);
    END LOOP;
END
$monrep$;
